mapper.delete:
/* wms-ctmaster-icgrade-sql-oracle.xml - deleteTworkInfoIcGrade */
DELETE
  FROM TWORK_INFO_IC_GRADE
 WHERE CTKEY = #{ctkey}

mapper.sql:
FROM TWORK_MST_IC IC INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = IC.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = IC.OWKEY LEFT JOIN TWORK_INFO_IC_GRADE GRADE ON GRADE.CTKEY = IC.CTKEY AND GRADE.OWKEY = IC.OWKEY AND GRADE.ICKEY = IC.ICKEY LEFT JOIN TWORK_MST_LC LC ON LC.CTKEY = IC.CTKEY AND LC.LCKEY = IC.LCKEY LEFT JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = LC.CTKEY AND ZN.ZNKEY = LC.ZNKEY LEFT JOIN TWORK_MST_ICBARCODE EA ON EA.CTKEY = IC.CTKEY AND EA.OWKEY = IC.OWKEY AND EA.ICKEY = IC.ICKEY AND EA.UOM = 'EA' LEFT JOIN TWORK_MST_ICBARCODE INN ON INN.CTKEY = IC.CTKEY AND INN.OWKEY = IC.OWKEY AND INN.ICKEY = IC.ICKEY AND INN.UOM = 'INN' LEFT JOIN TWORK_MST_ICBARCODE CTN ON CTN.CTKEY = IC.CTKEY AND CTN.OWKEY = IC.OWKEY AND CTN.ICKEY = IC.ICKEY AND CTN.UOM = 'CTN'
AND IC.CTKEY = COALESCE(#{ctkey}, #{sctkey})
AND GRADE.CNVRTOBQTY >= #{cnvrtfrqty}
AND GRADE.CNVRTOBQTY <= #{cnvrttoqty}
AND GRADE.CNVRTOBCBM >= #{cnvrtfrcbm}
AND GRADE.CNVRTOBCBM <= #{cnvrttocbm}
AND GRADE.ICKEY IS NOT NULL
AND COALESCE(GRADE.DSBTGRADECD, 'NULL') != COALESCE(IC.DSBTGRADECD, 'NULL')
AND COALESCE(GRADE.DSBTGRADECD, 'NULL') = COALESCE(IC.DSBTGRADECD, 'NULL')
AND 1 = 2

mapper.select:
/* wms-ctmaster-icgrade-sql-oracle.xml - selectTworkInfoIcGradeList */
SELECT '0' AS CHK , IC.CTKEY , CT.CTNM , IC.OWKEY , OW.OWNM , IC.ICKEY , IC.ICNM , IC.ICTYPECD , GRADE.ICKEY AS GR_ICKEY , GRADE.CRITDAY , GRADE.FROBDAY , GRADE.TOOBDAY , GRADE.OBQTY , GRADE.CTNOBQTY , GRADE.PLTOBQTY , GRADE.OBCBM , GRADE.AVGOBQTY , GRADE.AVGCTNOBQTY , GRADE.AVGPLTOBQTY , GRADE.AVGOBCBM , GRADE.CNVRTOBQTY , GRADE.CNVRTCTNOBQTY , GRADE.CNVRTPLTOBQTY , GRADE.CNVRTOBCBM , IC.LCKEY , LC.LCSTORGTYPECD , IC.DSBTGRADECD , GRADE.CMT , LC.ZNKEY AS LCZONE , EA.BARCODE AS EABARCODE , INN.BARCODE AS INNBARCODE , CTN.BARCODE AS CTNBARCODE
ORDER BY IC.CTKEY , IC.OWKEY , IC.ICKEY

/* wms-ctmaster-icgrade-sql-oracle.xml - selectTworkInfoIcGradeExcelList */ WITH T_CODE AS ( SELECT B.CTKEY , B.CTCDHDKEY , B.CTCDDTKEY , B.CTCDDTNM FROM TWORK_MST_CTCD_HD A INNER JOIN TWORK_MST_CTCD_DT B ON B.CTKEY = A.CTKEY AND B.CTCDHDKEY = A.CTCDHDKEY
AND A.DELYN = 'N' AND B.DELYN = 'N'
AND B.LAKEY = #{lakey}
AND A.CTCDHDKEY IN ('LCSTORGTYPECD', 'CTDSBTGRADECD')
) SELECT IC.CTKEY , CT.CTNM , IC.OWKEY , OW.OWNM , IC.ICKEY , IC.ICNM , GRADE.ICKEY AS GR_ICKEY , GRADE.CRITDAY , GRADE.FROBDAY , GRADE.TOOBDAY , COALESCE(GRADE.OBQTY, 0) AS OBQTY , COALESCE(GRADE.CTNOBQTY, 0) AS CTNOBQTY , COALESCE(GRADE.PLTOBQTY, 0) AS PLTOBQTY , COALESCE(GRADE.OBCBM, 0) AS OBCBM , COALESCE(GRADE.AVGOBQTY, 0) AS AVGOBQTY , COALESCE(GRADE.AVGCTNOBQTY, 0) AS AVGCTNOBQTY , COALESCE(GRADE.AVGPLTOBQTY, 0) AS AVGPLTOBQTY , COALESCE(GRADE.AVGOBCBM, 0) AS AVGOBCBM , COALESCE(GRADE.CNVRTOBQTY, 0) AS CNVRTOBQTY , COALESCE(GRADE.CNVRTCTNOBQTY, 0) AS CNVRTCTNOBQTY , COALESCE(GRADE.CNVRTPLTOBQTY, 0) AS CNVRTPLTOBQTY , COALESCE(GRADE.CNVRTOBCBM, 0) AS CNVRTOBCBM , IC.LCKEY , CD1.CTCDDTNM AS LCSTORGTYPECD , CD2.CTCDDTNM AS DSBTGRADECD , GRADE.CMT , LC.ZNKEY AS LCZONE , EA.BARCODE AS EABARCODE , INN.BARCODE AS INNBARCODE , CTN.BARCODE AS CTNBARCODE FROM TWORK_MST_IC IC INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = IC.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = IC.OWKEY LEFT JOIN TWORK_INFO_IC_GRADE GRADE ON GRADE.CTKEY = IC.CTKEY AND GRADE.OWKEY = IC.OWKEY AND GRADE.ICKEY = IC.ICKEY LEFT JOIN TWORK_MST_LC LC ON LC.CTKEY = IC.CTKEY AND LC.LCKEY = IC.LCKEY LEFT JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = LC.CTKEY AND ZN.ZNKEY = LC.ZNKEY LEFT JOIN TWORK_MST_ICBARCODE EA ON EA.CTKEY = IC.CTKEY AND EA.OWKEY = IC.OWKEY AND EA.ICKEY = IC.ICKEY AND EA.UOM = 'EA' LEFT JOIN TWORK_MST_ICBARCODE INN ON INN.CTKEY = IC.CTKEY AND INN.OWKEY = IC.OWKEY AND INN.ICKEY = IC.ICKEY AND INN.UOM = 'INN' LEFT JOIN TWORK_MST_ICBARCODE CTN ON CTN.CTKEY = IC.CTKEY AND CTN.OWKEY = IC.OWKEY AND CTN.ICKEY = IC.ICKEY AND CTN.UOM = 'CTN' LEFT JOIN T_CODE CD1 ON CD1.CTKEY = IC.CTKEY AND CD1.CTCDHDKEY = 'LCSTORGTYPECD' AND CD1.CTCDDTKEY = LC.LCSTORGTYPECD LEFT JOIN T_CODE CD2 ON CD2.CTKEY = IC.CTKEY AND CD2.CTCDHDKEY = 'CTDSBTGRADECD' AND CD2.CTCDDTKEY = IC.DSBTGRADECD
AND IC.CTKEY = COALESCE(#{ctkey}, #{sctkey})
AND GRADE.CNVRTOBQTY >= #{cnvrtfrqty}
AND GRADE.CNVRTOBQTY <= #{cnvrttoqty}
AND GRADE.CNVRTOBCBM >= #{cnvrtfrcbm}
AND GRADE.CNVRTOBCBM <= #{cnvrttocbm}
AND GRADE.ICKEY IS NOT NULL
AND COALESCE(GRADE.DSBTGRADECD, 'NULL') != COALESCE(IC.DSBTGRADECD, 'NULL')
AND COALESCE(GRADE.DSBTGRADECD, 'NULL') = COALESCE(IC.DSBTGRADECD, 'NULL')
AND 1 = 2
ORDER BY IC.CTKEY , IC.OWKEY , IC.ICKEY

mapper.update:
/* wms-ctmaster-icgrade-sql-oracle.xml - updateIcDsbtgradecd */
UPDATE TWORK_MST_IC
   SET DSBTGRADECD = #{newDsbtgradecd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
  AND OWKEY = #{owkey}
  AND ICKEY = #{ickey}

