/* wms-ctmaster-icgrade-sql-oracle.xml - selectDayAvgObQtyDupCheckCount */
SELECT COUNT(1)
  FROM TWORK_MST_DAY_AVG_OBQTY
 WHERE CTKEY = #{ctkey}

mapper.insert:
		/* wms-ctmaster-icgrade-sql-oracle.xml - insertTworkMstDayAvgObqty */
		INSERT INTO TWORK_MST_DAY_AVG_OBQTY (
			   CTKEY				/* 센터코드 */
             , AVDAYS               /* 가용일수 */
			 , CRITDAYS				/* 기준일수 */
			 , OBQTYCALCRITCD		/* 출고량산정기준코드 */
			 , INSERTDATE			/* 입력일자 */
			 , INSERTURKEY			/* 입력사용자 */
			 , UPDATEDATE			/* 수정일자 */
			 , UPDATEURKEY			/* 수정사용자 */
			 )
		VALUES (
		       #{ctkey}
             , #{avdays}
             , #{critdays}
             , #{obqtycalcritcd}
             , #{sysdate}
             , #{surkey}
             , #{sysdate}
             , #{surkey}
			 )

mapper.update:
		/* wms-ctmaster-icgrade-sql-oracle.xml - updateTworkMstDayAvgObqty */
		UPDATE TWORK_MST_DAY_AVG_OBQTY
		   SET AVDAYS = #{avdays}
             , CRITDAYS = #{critdays}
		     , OBQTYCALCRITCD = #{obqtycalcritcd}
			 , UPDATEDATE = #{sysdate}
			 , UPDATEURKEY = #{surkey}
		 WHERE CTKEY = #{ctkey}

mapper.select:
/* wms-ctmaster-icgrade-sql-oracle.xml - selectIcGradeMstList */ SELECT '0' AS CHK , GD.CTKEY , GD.DSBTGRADECD , CD.CTCDDTNM AS DSBTGRADECDNM , GD.CNVRTQTY , GD.CNVRTUOM , GD.CNVRTDIVCD , GD.CNVRTCBM , GD.CNVRTCBMDIVCD , GD.CMT , GD.INSERTDATE , GD.INSERTURKEY , GD.UPDATEDATE , GD.UPDATEURKEY FROM TWORK_MST_GRADE_DT GD LEFT JOIN ( SELECT B.CTKEY , B.CTCDHDKEY , B.CTCDDTKEY , B.CTCDDTNM , B.CTCDDTORD FROM TWORK_MST_CTCD_HD A INNER JOIN TWORK_MST_CTCD_DT B ON B.CTKEY = A.CTKEY AND B.CTCDHDKEY = A.CTCDHDKEY
AND A.DELYN = 'N' AND B.DELYN = 'N'
AND B.LAKEY = #{lakey}
AND A.CTCDHDKEY = 'CTDSBTGRADECD'
) CD ON CD.CTKEY = GD.CTKEY AND CD.CTCDHDKEY = 'CTDSBTGRADECD' AND CD.CTCDDTKEY = GD.DSBTGRADECD WHERE GD.CTKEY = COALESCE(#{ctkey}, #{sctkey}) ORDER BY CD.CTCDDTORD

