mapper.insert:
/* wms-ctmaster-icgrade-sql-oracle.xml - insertIcGradeMstDt */
INSERT INTO TWORK_MST_GRADE_DT (
	   CTKEY
	 , DSBTGRADECD
	 , CNVRTQTY
	 , CNVRTUOM
	 , CNVRTDIVCD
	 , CNVRTCBM
	 , CNVRTCBMDIVCD
	 , CMT
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
     )
VALUES (
	   #{ctkey}
	 , #{dsbtgradecd}
	 , #{cnvrtqty}
	 , #{cnvrtuom}
	 , #{cnvrtdivcd}
	 , #{cnvrtcbm}
	 , #{cnvrtcbmdivcd}
	 , #{cmt}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

mapper.update:
/* wms-ctmaster-icgrade-sql-oracle.xml - updateIcGradeMstDt */
UPDATE TWORK_MST_GRADE_DT
   SET CNVRTQTY = #{cnvrtqty}
     , CNVRTUOM = #{cnvrtuom}
     , CNVRTCBM = #{cnvrtcbm}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND DSBTGRADECD = #{dsbtgradecd}

